    fwrite(s, sizeof(Student), 1, f);
}

int read_student(FILE *f, int index, Student *s) {
    fseek(f, index * (long)sizeof(Student), SEEK_SET);
    return fread(s, sizeof(Student), 1, f) == 1;
}

